import { Component, OnInit } from '@angular/core';
import {UserService} from './../services/user.service';
import { IonInput, ModalController, NavController, ToastController } from '@ionic/angular';
import { Router } from '@angular/router';
import { environment } from 'src/environments/environment';

@Component({
  selector: 'app-start',
  templateUrl: './start.page.html',
  styleUrls: ['./start.page.scss'],
})
export class StartPage implements OnInit {

  constructor(private userService:UserService, private router: Router, private nav:NavController,) { }

  ngOnInit() {
    let phone =  localStorage.getItem(environment.prefix + 'user_phone');
    let password = localStorage.getItem(environment.prefix + 'user_password');
    this.userService.login(phone, password).then(response =>{

      if (response.error) {
        this.nav.navigateRoot(['login']);
      } else {
        this.nav.navigateRoot(['orders']);
      }

    })
  }

}
